utiva parcial semestral com famílias em julho","itens":[{"id":"s6r","texto":"Elaborar apresentação da evolução clínica","feito":false},{"id":"s6s","texto":"Apresentar devolutiva na TV do consultório","feito":false},{"id":"s6t","texto":"Alinhar próximos objetivos terapêuticos","feito":false}]},{"id":"s6u","titulo":"Organizar devolutiva anual em dezembro","itens":[{"id":"s6v","texto":"Elaborar apresentação anual da evolução clínica","feito":false},{"id":"s6w","texto":"Apresentar devolutiva na TV do consultório","feito":false},{"id":"s6x","texto":"Discutir necessidade de continuidade terapêutica para o ano seguinte","feito":false},{"id":"s6y","texto":"Realizar agendamento das devolutivas familiares","feito":false}]}],"recursos":[],"rotinas":[{"id":"s6z","texto":"O plano terapêutico deve ser criado em até 7 dias após finalização da avaliação/devolutiva familiar"},{"id":"s70","texto":"O plano terapêutico obrigatoriamente deve ser validado antes do início da intervenção"},{"id":"s71","texto":"As sessões terapêuticas acontecem semanalmente com duração média de 50 minutos"},{"id":"s72","texto":"O registro clínico deve ser realizado preferencialmente no mesmo dia do atendimento (prazo máximo até o final da semana vigente)"},{"id":"s73","texto":"O registro de presença ou falta deve ser realizado ao final de cada sessão"},{"id":"s74","texto":"Feedbacks familiares devem acontecer de forma contínua e breve ao final dos atendimentos quando necessário"},{"id":"s75","texto":"O acompanhamento escolar deve ocorrer minimamente no início, meio e final do ano"},{"id":"s76","texto":"A devolutiva parcial com famílias deve ocorrer em julho"},{"id":"s77","texto":"A devolutiva anual deve ocorrer em dezembro"}],"riscos":[{"id":"s78","ponto_critico":"Falta de rotina fixa de supervisão clínica","acao":""},{"id":"s79","ponto_critico":"Falta de padronização do registro terapêutico periódico","acao":""},{"id":"s7a","ponto_critico":"Registros clínicos atrasados ou incompletos no Sisclin","acao":""},{"id":"s7b","ponto_critico":"Não realização do registro de frequência do paciente","acao":""},{"id":"s7c","ponto_critico":"Sobrecarga operacional da direção clínica","acao":""},{"id":"s7d","ponto_critico":"Atraso na criação dos planos terapêuticos","acao":""},{"id":"s7e","ponto_critico":"Baixa adesão familiar às orientações e atividades de casa","acao":""},{"id":"s7f","ponto_critico":"Faltas frequentes dos pacientes","acao":""},{"id":"s7g","ponto_critico":"Dificuldade da família em perceber evolução no curto prazo","acao":""},{"id":"s7h","ponto_critico":"Ausência de fluxo padronizado para acompanhamento escolar","acao":""},{"id":"s7i","ponto_critico":"Dependência excessiva da direção clínica para tomada de decisão terapêutica","acao":""}],"acoes":[{"id":"s7j","texto":"Acionar direção clínica em casos de atraso na criação do plano terapêutico"},{"id":"s7k","texto":"Realizar revisão semanal dos prontuários para identificação de registros pendentes"},{"id":"s7l","texto":"Solicitar atualização imediata do Sisclin em casos de prontuários incompletos"},{"id":"s7m","texto":"Reforçar alinhamentos terapêuticos com equipe em casos de inconsistência clínica"},{"id":"s7n","texto":"Agendar reunião clínica extraordinária quando houver dificuldade significativa na evolução terapêutica"},{"id":"s7o","texto":"Reforçar orientações familiares em casos de baixa adesão às atividades propostas"},{"id":"s7p","texto":"Realizar contato ativo com responsáveis em casos de faltas frequentes"},{"id":"s7q","texto":"Reavaliar estratégias terapêuticas quando não houver evolução observável"},{"id":"s7r","texto":"Registrar todas as intercorrências relevantes no prontuário clínico"}],"metricas":[{"id":"s7s","indicador":"Frequência/adesão dos pacientes ao acompanhamento","objetivo":"Monitorar continuidade terapêutica · Sisclin","valor_atual":"","unidade":""},{"id":"s7t","indicador":"Percentual de devolutivas semestrais realizadas","objetivo":"Garantir alinhamento contínuo com famílias · Agenda + registros internos","valor_atual":"","unidade":""},{"id":"s7u","indicador":"Percentual de planos terapêuticos criados no prazo","objetivo":"Reduzir início da intervenção sem direcionamento · Sisclin + controle interno","valor_atual":"","unidade":""},{"id":"s7v","indicador":"Percentual de registros clínicos realizados no prazo","objetivo":"Garantir prontuários atualizados e segurança documental · Sisclin","valor_atual":"","unidade":""}],"tarefas_pendentes":[{"id":"scy","texto":"Estruturar rotina fixa de supervisão clínica","feito":false},{"id":"scz","texto":"Padronizar revisão terapêutica periódica","feito":false},{"id":"sd0","texto":"Estruturar rotina fixa de devolutivas parciais","feito":false},{"id":"sd1","texto":"Criar mecanismo de controle dos registros clínicos no Sisclin","feito":false},{"id":"sd2","texto":"Criar mecanismo de acompanhamento dos planos terapêuticos pendentes","feito":false},{"id":"sd3","texto":"Inserir links oficiais dos templates/modelos utilizados","feito":false},{"id":"sd4","texto":"Estruturar fluxo oficial de acompanhamento escolar","feito":false}]}$j$::jsonb
